&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;!DOCTYPE mapper        PUBLIC &quot;-//mybatis.org//DTD Mapper 3.0//EN&quot;        &quot;http://mybatis.org/dtd/mybatis-3-mapper.dtd&quot;&gt;&lt;mapper namespace=&quot;com.lh.mybatisx.mapper.UserMapper&quot;&gt;    &lt;resultMap id=&quot;BaseResultMap&quot; type=&quot;com.lh.mybatisx.pojo.User&quot;&gt;            &lt;id property=&quot;id&quot; column=&quot;id&quot; jdbcType=&quot;BIGINT&quot;/&gt;            &lt;result property=&quot;userName&quot; column=&quot;user_name&quot; jdbcType=&quot;VARCHAR&quot;/&gt;            &lt;result property=&quot;age&quot; column=&quot;age&quot; jdbcType=&quot;INTEGER&quot;/&gt;            &lt;result property=&quot;sex&quot; column=&quot;sex&quot; jdbcType=&quot;INTEGER&quot;/&gt;            &lt;result property=&quot;email&quot; column=&quot;email&quot; jdbcType=&quot;VARCHAR&quot;/&gt;            &lt;result property=&quot;isDeleted&quot; column=&quot;is_deleted&quot; jdbcType=&quot;INTEGER&quot;/&gt;    &lt;/resultMap&gt;    &lt;sql id=&quot;Base_Column_List&quot;&gt;        id,user_name,age,        sex,email,is_deleted    &lt;/sql&gt;    &lt;insert id=&quot;insertSelective&quot;&gt;        insert into user        &lt;trim prefix=&quot;(&quot; suffix=&quot;)&quot; suffixOverrides=&quot;,&quot;&gt;            &lt;if test=&quot;id != null&quot;&gt;id,&lt;/if&gt;            &lt;if test=&quot;userName != null&quot;&gt;user_name,&lt;/if&gt;            &lt;if test=&quot;age != null&quot;&gt;age,&lt;/if&gt;            &lt;if test=&quot;sex != null&quot;&gt;sex,&lt;/if&gt;            &lt;if test=&quot;email != null&quot;&gt;email,&lt;/if&gt;            &lt;if test=&quot;isDeleted != null&quot;&gt;is_deleted,&lt;/if&gt;        &lt;/trim&gt;        values        &lt;trim prefix=&quot;(&quot; suffix=&quot;)&quot; suffixOverrides=&quot;,&quot;&gt;            &lt;if test=&quot;id != null&quot;&gt;#&#123;id,jdbcType=BIGINT&#125;,&lt;/if&gt;            &lt;if test=&quot;userName != null&quot;&gt;#&#123;userName,jdbcType=VARCHAR&#125;,&lt;/if&gt;            &lt;if test=&quot;age != null&quot;&gt;#&#123;age,jdbcType=INTEGER&#125;,&lt;/if&gt;            &lt;if test=&quot;sex != null&quot;&gt;#&#123;sex,jdbcType=INTEGER&#125;,&lt;/if&gt;            &lt;if test=&quot;email != null&quot;&gt;#&#123;email,jdbcType=VARCHAR&#125;,&lt;/if&gt;            &lt;if test=&quot;isDeleted != null&quot;&gt;#&#123;isDeleted,jdbcType=INTEGER&#125;,&lt;/if&gt;        &lt;/trim&gt;    &lt;/insert&gt;    &lt;delete id=&quot;deleteByIdAndUserName&quot;&gt;        delete        from user        where id = #&#123;id,jdbcType=NUMERIC&#125;          AND user_name = #&#123;userName,jdbcType=VARCHAR&#125;    &lt;/delete&gt;    &lt;update id=&quot;updateAgeAndSexById&quot;&gt;        update user        set age = #&#123;age,jdbcType=NUMERIC&#125;,            sex = #&#123;sex,jdbcType=NUMERIC&#125;        where id = #&#123;id,jdbcType=NUMERIC&#125;    &lt;/update&gt;    &lt;select id=&quot;selectAgeAndSexByAgeBetween&quot; resultMap=&quot;BaseResultMap&quot;&gt;        select age, sex        from user        where age between #&#123;beginAge,jdbcType=INTEGER&#125; and #&#123;endAge,jdbcType=INTEGER&#125;    &lt;/select&gt;    &lt;select id=&quot;selectAllOrderByAgeDesc&quot; resultMap=&quot;BaseResultMap&quot;&gt;        select        &lt;include refid=&quot;Base_Column_List&quot;/&gt;        from user        order by age desc    &lt;/select&gt;&lt;/mapper&gt;

