  &lt;/dependency&gt;    &lt;!-- jsr303 --&gt;    &lt;dependency&gt;     &lt;groupId&gt;org.hibernate.validator&lt;/groupId&gt;      &lt;artifactId&gt;hibernate-validator&lt;/artifactId&gt;      &lt;version&gt;8.0.1.Final&lt;/version&gt;   &lt;/dependency&gt;    &lt;dependency&gt;     &lt;groupId&gt;org.hibernate.validator&lt;/groupId&gt;      &lt;artifactId&gt;hibernate-validator-annotation-processor&lt;/artifactId&gt;      &lt;version&gt;8.0.1.Final&lt;/version&gt;   &lt;/dependency&gt;    &lt;!-- mybatis 依赖 --&gt;    &lt;dependency&gt;     &lt;groupId&gt;org.mybatis&lt;/groupId&gt;      &lt;artifactId&gt;mybatis&lt;/artifactId&gt;      &lt;version&gt;3.5.14&lt;/version&gt;   &lt;/dependency&gt;    &lt;!-- mysql 驱动 --&gt;    &lt;dependency&gt;     &lt;groupId&gt;mysql&lt;/groupId&gt;      &lt;artifactId&gt;mysql-connector-java&lt;/artifactId&gt;      &lt;version&gt;8.0.33&lt;/version&gt;   &lt;/dependency&gt;    &lt;!-- 分页 --&gt;    &lt;dependency&gt;     &lt;groupId&gt;com.github.pagehelper&lt;/groupId&gt;      &lt;artifactId&gt;pagehelper&lt;/artifactId&gt;      &lt;version&gt;6.1.0&lt;/version&gt;   &lt;/dependency&gt;    &lt;!-- 整合需要 --&gt;    &lt;!-- 加载 spring 容器 --&gt;    &lt;dependency&gt;     &lt;groupId&gt;org.springframework&lt;/groupId&gt;      &lt;artifactId&gt;spring-web&lt;/artifactId&gt;      &lt;version&gt;6.1.2&lt;/version&gt;   &lt;/dependency&gt;    &lt;!-- 整合 mybatis --&gt;    &lt;dependency&gt;     &lt;groupId&gt;org.mybatis&lt;/groupId&gt;      &lt;artifactId&gt;mybatis-spring&lt;/artifactId&gt;      &lt;version&gt;3.0.3&lt;/version&gt;   &lt;/dependency&gt;    &lt;!-- druid --&gt;    &lt;dependency&gt;     &lt;groupId&gt;com.alibaba&lt;/groupId&gt;      &lt;artifactId&gt;druid&lt;/artifactId&gt;      &lt;version&gt;1.2.16&lt;/version&gt;   &lt;/dependency&gt;    &lt;!-- lombok --&gt;    &lt;dependency&gt;     &lt;groupId&gt;org.projectlombok&lt;/groupId&gt;      &lt;artifactId&gt;lombok&lt;/artifactId&gt;      &lt;version&gt;1.18.30&lt;/version&gt;   &lt;/dependency&gt;    &lt;!-- logback 做日志 --&gt;    &lt;dependency&gt;     &lt;groupId&gt;ch.qos.logback&lt;/groupId&gt;      &lt;artifactId&gt;logback-classic&lt;/artifactId&gt;      &lt;version&gt;1.4.14&lt;/version&gt;   &lt;/dependency&gt; &lt;/dependencies&gt; 

3.2 加入日志文件将 logback.xml 放在 resources 目录下
&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot; ?&gt;&lt;configuration debug=&quot;true&quot;&gt;    &lt;!-- 指定日志输出的位置, ConsoleAppender 表示输出到控制台 --&gt;    &lt;appender name=&quot;STDOUT&quot;              class=&quot;ch.qos.logback.core.ConsoleAppender&quot;&gt;        &lt;encoder&gt;            &lt;!-- 日志输出格式 --&gt;            &lt;!-- 按照顺序分别是: 时间、日志级别、线程名称、打印日志的类、日志主题内容、换行--&gt;            &lt;pattern&gt;[%d&#123;HH:mm:ss.SSS&#125;] [%-5level] [%thread] [%logger] [%msg]%n&lt;/pattern&gt;            &lt;charset&gt;UTF-8&lt;/charset&gt;        &lt;/encoder&gt;    &lt;/appender&gt;        &lt;!-- 设置全局日志级别, 日志级别有 TRACE、DEBUG、INFO、WARN、ERROR --&gt;    &lt;root level=&quot;DEBUG&quot;&gt;        &lt;!-- 指定打印日志的 appender, 这里通过 STDOUT 引用了前面配置的 appender --&gt;        &lt;appender-ref ref=&quot;STDOUT&quot;/&gt;    &lt;/root&gt;    &lt;!-- 根据特殊需求指定局部日志级别, 可以是包名或全类名 --&gt;    &lt;logger name=&quot;com.lh.mybatis&quot; level=&quot;DEBUG&quot;/&gt;&lt;/configuration&gt;

3.3 SpringMVC 层配置com.lh.config 包下创建类 WebMvcJavaConfig, 该配置类做的工作有如下

将 @Controller 标识的类放入容器 (@ComponentScan 解决)
全局异常处理器 (@ComponentScan 扫描异常处理器所在包)
handlerMapping handlerAdapter (@EnableWebMvc 解决)
静态资源处理
jsp 视图解析器前后缀
json 转换器 (@EnableWebMvc 解决)
拦截器

@Configuration@EnableWebMvc@ComponentScan(&#123;&quot;com.lh.controller&quot;, &quot;com.lh.exceptionhandler&quot;&#125;)public class WebMvcJavaConfig implements WebMvcConfigurer &#123;    // 静态资源处理    @Override    public void configureDefaultServletHandling(DefaultServletHandlerConfigurer configurer) &#123;        configurer.enable();    &#125;    // 视图解析器    @Override    public void configureViewResolvers(ViewResolverRegistry registry) &#123;        registry.jsp(&quot;/WEB-INF/views/&quot;, &quot;.jsp&quot;);    &#125;    // 加拦截器    @Override    public void addInterceptors(InterceptorRegistry registry) &#123;        // registry.addInterceptor(); 加拦截器    &#125;&#125;

3.4 servic、aop、tx 配置所要做的工作有如下

service
开启 aop 注解的支持 aspect
tx 声明式事务管理：1. 对应的事务管理器实现 2. 开启事务注解支持 @Transational

@Configuration@EnableAspectJAutoProxy@EnableTransactionManagement@ComponentScan(&quot;com.lh.service&quot;)public class ServiceJavaConfig &#123;    @Bean    public TransactionManager transactionManager(DataSource dataSource)&#123;        DataSourceTransactionManager dataSourceTransactionManager = new DataSourceTransactionManager();        dataSourceTransactionManager.setDataSource(dataSource);        return dataSourceTransactionManager;    &#125;&#125;


@EnableAspectJAutoProxy等价于原来的
&lt;!-- 开启 aspectj 自动代理, 为目标对象生成代理, 即 @Aspect 标注的类 --&gt;&lt;aop:aspectj-autoproxy /&gt;

然后看事务的配置, 我们观察原来 XML 文件配置方式
&lt;!-- 引入外部属性文件, 创建数据源对象--&gt;&lt;context:property-placeholder location=&quot;classpath:jdbc.properties&quot;/&gt;&lt;!-- druid 数据源 --&gt;&lt;bean id=&quot;druidDataSource&quot; class=&quot;com.alibaba.druid.pool.DruidDataSource&quot;&gt;    &lt;property name=&quot;url&quot; value=&quot;$&#123;jdbc.url&#125;&quot;/&gt;    &lt;property name=&quot;password&quot; value=&quot;$&#123;jdbc.password&#125;&quot;/&gt;    &lt;property name=&quot;driverClassName&quot; value=&quot;$&#123;jdbc.driver&#125;&quot;/&gt;    &lt;property name=&quot;username&quot; value=&quot;$&#123;jdbc.user&#125;&quot;/&gt;&lt;/bean&gt;  &lt;!-- 创建 jdbcTemplate 对象, 注入数据源 --&gt;&lt;bean id=&quot;jdbcTemplate&quot; class=&quot;org.springframework.jdbc.core.JdbcTemplate&quot;&gt;    &lt;property name=&quot;dataSource&quot; ref=&quot;druidDataSource&quot;/&gt;&lt;/bean&gt;&lt;!-- 事务管理器 --&gt;&lt;bean id=&quot;transactionManager&quot; class=&quot;org.springframework.jdbc.datasource.DataSourceTransactionManager&quot;&gt;    &lt;property name=&quot;dataSource&quot; ref=&quot;druidDataSource&quot;/&gt;&lt;/bean&gt;&lt;!--    开启事务的注解驱动    通过注解 @Transactional 所标识的方法或标识的类中所有的方法，都会被事务管理器管理事务--&gt;&lt;!-- transaction-manager 属性的默认值是 transactionManager, 如果事务管理 bean 的 id 正好是就是这个默认值, 则可以省略这个属性 --&gt;&lt;tx:annotation-driven transaction-manager=&quot;transactionManager&quot; /&gt;


还是很长的, 因为事务是和数据库关联的首先是 Druid 数据源, 这里面还没有配置, 需要我们在整合持久层时编写, 它实际上就是我们上面的参数 (DataSource dataSource), 当我们将数据源加入容器后, 这个参数会被自动注入, 这样事务管理器也就注入成功了。我们这里的方法配置的是事务管理器。注解 @EnableTransactionManagement 等价于开启事务的注解驱动


3.5 Mybatis 整合3.5.1 整合思路原来的核心 API
// 1. 读取外部配置文件 (mybatis-config.xml)InputStream ips = Resources.getResourceAsStream(&quot;mybatis-config.xml&quot;);// 2. 根据配置文件创建 sqlSessionFactorySqlSessionFactory sqlSessionFactory = new SqlSessionFactoryBuilder().build(ips);// 3. 根据 sqlSessionFactory 创建 sqlSession (每次业务创建一个, 用完就释放)SqlSession sqlSession = sqlSessionFactory.openSession();// 4. 获取接口的代理对象 (代理技术) 调用代理对象的方法, 就会查找 mapper 接口的方法EmployeeMapper mapper = sqlSession.getMapper(EmployeeMapper.class);Employee employee = mapper.queryById(1);System.out.println(&quot;employee = &quot; + employee);// 5. 提交事务(不是查询就要提交, 不提交这里的增删改不会生效)和释放资源sqlSession.commit(); // 这里是查询, 可以不写提交sqlSession.close();


SqlSessionFactoryBuilder主要用来获取 SqlSessionFactory, 用一次就可以了, 所以不需要加入 IOC

SqlSessionFactory一旦创建就应该在应用运行期间一致存在, 所以运行期间不要重复创建多次, 需要加入 IOC

SqlSession每个线程都应该有它自己的 SqlSession 实例。SqlSession 的实例不是线程安全的, 因此不能放在 IOC 中被共享

Mapper 映射器实例放在 IOC 容器中, 这样当我们需要使用时直接注入即可。
@Autowiredprivate EmployeeMapper employeeMapper;


反之, 如果我们不放在 IOC 容器中, 我们就需要在使用的时候再书写代码, 就很麻烦
@Autowiredprivate SqlSessionFactory sqlSessionFactory;public void method()&#123;    SqlSession sqlSession = sqlSessionFactory.openSession();    EmployeeMapper mapper = sqlSession.getMapper(EmployeeMapper.class);&#125;

所以需要放入 IOC 容器的有 SqlSessionFactory 和 mapper 实例
SqlSessionFactory 放入容器如何放？可以按照原来的方式放入
@Beanpublic SqlSessionFactory sqlSessionFactory()&#123;        InputStream ips = Resources.getResourceAsStream(&quot;mybatis-config.xml&quot;);        SqlSessionFactory sqlSessionFactory = new SqlSessionFactoryBuilder().build(ips);        return sqlSessionFactory;&#125;

但是过程比较繁琐, mybatis 提供了封装 SqlSessionFactory 和 mapper 实例化逻辑的 FactoryBean 组件(Spring提供的) !!! 使用这种方式, 下面会用到
3.5.2 mybatis 整合准备数据库连接信息 在 resources 目录下的 jdbc.properties
jdbc.driver=com.mysql.cj.jdbc.Driverjdbc.url=jdbc:mysql://localhost:3306/mybatis-example?characterEncoding=utf-8&amp;useSSL=falsejdbc.user=rootjdbc.password=mysql

如果支持多语句, jdbc.url 后面还要加上 allowMultiQueries=true
3.5.2.1 通过 XML 整合
保留 mybatis-config.xml, 但是数据库连接信息交给 Druid 连接池配置, mapper 接口的包指定也不需要了
&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot; ?&gt;&lt;!DOCTYPE configuration        PUBLIC &quot;-//mybatis.org//DTD Config 3.0//EN&quot;        &quot;https://mybatis.org/dtd/mybatis-3-config.dtd&quot;&gt;&lt;configuration&gt;    &lt;settings&gt;        &lt;setting name=&quot;mapUnderscoreToCamelCase&quot; value=&quot;true&quot;/&gt;        &lt;!-- 开启 logback 日志输出 --&gt;        &lt;setting name=&quot;logImpl&quot; value=&quot;SLF4J&quot; /&gt;    &lt;/settings&gt;        &lt;typeAliases&gt;        &lt;package name=&quot;com.lh.pojo&quot;/&gt;    &lt;/typeAliases&gt;        &lt;plugins&gt;        &lt;plugin interceptor=&quot;com.github.pagehelper.PageInterceptor&quot;&gt;            &lt;property name=&quot;helperDialect&quot; value=&quot;mysql&quot;/&gt;        &lt;/plugin&gt;    &lt;/plugins&gt;&lt;/configuration&gt;

在 com.lh.config 中创建 MapperJavaConfig
@Configurationpublic class MapperJavaConfig &#123;    // SqlSessionFactory 加入IOC容器    // mybatis 提供了 sqlSessionFactoryBean, 我们通过 getObject() 方法来获取 sqlSessionFactory    // 方式1: 外部指定 mybatis-config.xml    @Bean    public SqlSessionFactoryBean sqlSessionFactory(DataSource dataSource)&#123;        SqlSessionFactoryBean sqlSessionFactoryBean = new SqlSessionFactoryBean();        // 指定配置文件等信息        // 1.指定连接池        sqlSessionFactoryBean.setDataSource(dataSource);        // 2.指定外部的 mybatis 配置文件 [import org.springframework.core.io.Resource;]        Resource resource = new ClassPathResource(&quot;mybatis-config.xml&quot;);        sqlSessionFactoryBean.setConfigLocation(resource);        return sqlSessionFactoryBean;    &#125;    @Bean    public MapperScannerConfigurer mapperScannerConfigurer()&#123;        // 为 mapper 接口创建代理对象        MapperScannerConfigurer mapperScannerConfigurer = new MapperScannerConfigurer();        mapperScannerConfigurer.setBasePackage(&quot;com.lh.mapper&quot;); // mapper接口和mapper.xml所在的共同包        return mapperScannerConfigurer;    &#125;&#125;

创建 DataSourceJavaConfig
@Configuration@PropertySource(&quot;classpath:jdbc.properties&quot;)public class DataSourceJavaConfig &#123;    @Value(&quot;$&#123;jdbc.user&#125;&quot;)    private String user;    @Value(&quot;$&#123;jdbc.password&#125;&quot;)    private String password;    @Value(&quot;$&#123;jdbc.url&#125;&quot;)    private String url;    @Value(&quot;$&#123;jdbc.driver&#125;&quot;)    private String driver;    // druid 连接池    @Bean    public DataSource dataSource()&#123;        DruidDataSource dataSource = new DruidDataSource();        dataSource.setUsername(user);        dataSource.setPassword(password);        dataSource.setUrl(url);        dataSource.setDriverClassName(driver);        return dataSource;    &#125;&#125;

3.5.2.2 通过配置类 (推荐)
不使用 mybatis-config.xml 配置文件, 所有配置信息 settings、plugins、typeAlias 等都在 SqlSessionFactoryBean 中指定
@Configurationpublic class MapperJavaConfig &#123;    // SqlSessionFactory 加入IOC容器    // mybatis 提供了 sqlSessionFactoryBean, 我们通过 getObject() 方法来获取 sqlSessionFactory    @Bean    public SqlSessionFactoryBean sqlSessionFactory(DataSource dataSource)&#123;        SqlSessionFactoryBean sqlSessionFactoryBean = new SqlSessionFactoryBean();        // 1.指定连接池        sqlSessionFactoryBean.setDataSource(dataSource);        // 2.指定 mybatis 配置, setting        org.apache.ibatis.session.Configuration configuration =                new org.apache.ibatis.session.Configuration();        configuration.setMapUnderscoreToCamelCase(true);        configuration.setLogImpl(Slf4jImpl.class);        configuration.setAutoMappingBehavior(AutoMappingBehavior.FULL);        sqlSessionFactoryBean.setConfiguration(configuration);        // typeAlias        sqlSessionFactoryBean.setTypeAliasesPackage(&quot;com.lh.pojo&quot;);        // 插件配置 plugins        PageInterceptor pageInterceptor = new PageInterceptor();        Properties properties = new Properties();        properties.setProperty(&quot;helperDialect&quot;, &quot;mysql&quot;);        pageInterceptor.setProperties(properties);        sqlSessionFactoryBean.addPlugins(pageInterceptor);        return sqlSessionFactoryBean;    &#125;    @Bean    public MapperScannerConfigurer mapperScannerConfigurer()&#123;        // 为 mapper 接口创建代理对象        MapperScannerConfigurer mapperScannerConfigurer = new MapperScannerConfigurer();        mapperScannerConfigurer.setBasePackage(&quot;com.lh.mapper&quot;); // mapper接口和mapper.xml所在的共同包        return mapperScannerConfigurer;    &#125;&#125;

创建 DataSourceJavaConfig
@Configuration@PropertySource(&quot;classpath:jdbc.properties&quot;)public class DataSourceJavaConfig &#123;    @Value(&quot;$&#123;jdbc.user&#125;&quot;)    private String user;    @Value(&quot;$&#123;jdbc.password&#125;&quot;)    private String password;    @Value(&quot;$&#123;jdbc.url&#125;&quot;)    private String url;    @Value(&quot;$&#123;jdbc.driver&#125;&quot;)    private String driver;    // druid 连接池    @Bean    public DataSource dataSource()&#123;        DruidDataSource dataSource = new DruidDataSource();        dataSource.setUsername(user);        dataSource.setPassword(password);        dataSource.setUrl(url);        dataSource.setDriverClassName(driver);        return dataSource;    &#125;&#125;



3.5.3 配置类初始化及测试在 com.lh.config 下创建类 SpringIoCInit
public class SpringIoCInit extends AbstractAnnotationConfigDispatcherServletInitializer &#123;    // root ioc 容器配置类    @Override    protected Class&lt;?&gt;[] getRootConfigClasses() &#123;        return new Class[]&#123;ServiceJavaConfig.class, MapperJavaConfig.class, DataSourceJavaConfig.class&#125;;    &#125;    // web ioc 容器的配置类    @Override    protected Class&lt;?&gt;[] getServletConfigClasses() &#123;        return new Class[]&#123;WebMvcJavaConfig.class&#125;;    &#125;    // dispatcherServlet 的拦截路径    @Override    protected String[] getServletMappings() &#123;        return new String[]&#123;&quot;/&quot;&#125;;    &#125;&#125;

service 层、controller 层、mapper 层 三层开搞
mapper 层
public interface EmployeeMapper &#123;    List&lt;Employee&gt; queryList();&#125;

mapper.xml
&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot; ?&gt;&lt;!DOCTYPE mapper        PUBLIC &quot;-//mybatis.org//DTD Mapper 3.0//EN&quot;        &quot;https://mybatis.org/dtd/mybatis-3-mapper.dtd&quot;&gt;&lt;mapper namespace=&quot;com.lh.mapper.EmployeeMapper&quot;&gt;    &lt;select id=&quot;queryList&quot; resultType=&quot;employee&quot;&gt;        select * from t_emp    &lt;/select&gt;&lt;/mapper&gt;

