controller 层
@RestController@RequestMapping(&quot;emp&quot;)public class EmployeeController &#123;    @Autowired    private EmployeeService employeeService;    @GetMapping(&quot;/find&quot;)    public List&lt;Employee&gt; find()&#123;        return employeeService.findAll();    &#125;&#125;

