12.6.4 Search.vuehttps://api.github.com/search/users是github提供的查询用户的接口，可以供程序员访问，访问方式是在其后加上`?q=`，这样github会把相关用户返回。 &lt;template&gt; &lt;section class=&quot;jumbotron&quot;&gt; &lt;h3 class=&quot;jumbotron-heading&quot;&gt;Search Github Users&lt;/h3&gt; &lt;div&gt; &lt;input type=&quot;text&quot; placeholder=&quot;enter the name you search&quot; v-model=&quot;keyWord&quot;/&gt; &lt;button @click=&quot;getUsers&quot;&gt;Search&lt;/button&gt; &lt;/div&gt; &lt;/section&gt;&lt;/template&gt;&lt;script&gt; import axios from &#x27;axios&#x27; export default &#123; name:&#x27;Search&#x27;, data() &#123; return &#123; keyWord:&#x27;&#x27; &#125; &#125;, methods: &#123; getUsers()&#123; //请求前更新List的数据 this.$bus.$emit(&#x27;updateListData&#x27;,&#123;isLoading:true,errMsg:&#x27;&#x27;,users:[],isFirst:false&#125;) axios.get(`https://api.github.com/search/users?q=$&#123;this.keyWord&#125;`).then( response =&gt; &#123; console.log(&#x27;请求成功了&#x27;) //请求成功后更新List的数据 this.$bus.$emit(&#x27;updateListData&#x27;,&#123;isLoading:false,errMsg:&#x27;&#x27;,users:response.data.items&#125;) &#125;, error =&gt; &#123; //请求后更新List的数据 this.$bus.$emit(&#x27;updateListData&#x27;,&#123;isLoading:false,errMsg:error.message,users:[]&#125;) &#125; ) &#125; &#125; &#125;&lt;/script&gt;
