import Vue from &#x27;vue&#x27;import App from &#x27;./App.vue&#x27;//按需引入import &#123; Button,Row &#125; from &#x27;element-ui&#x27;Vue.config.productionTip = falseVue.component(Button.name, Button); // 可以不适用Button.name，自己命名也可以，命名为什么，该组件标签名就为什么，比如Vue.component(&#x27;gouge-button&#x27;, Button)Vue.component(Row.name, Row);/* 或写为 * Vue.use(Button) * Vue.use(Row) */new Vue(&#123; el:&quot;#app&quot;, render: h =&gt; h(App),&#125;)
