17. 网站 bootCDN：下载第三方js代码的网站 npm：通过npm下载包的网站，里面会有相关包的详细教程

1、ajax简介 ajax全称为Asynchronous JavaScript And XML，就是异步的JS 和XML 通过AJAX可以再浏览器中向服务器发送异步请求，最大的优势：无刷新获取数据 ajax不是新的编程语言，而是一种将现有的标准组合在一起使用的新方式
2、XML简介 可扩展标记语言
被设计用来传输和存储数据
XML和HTML类似，不同的是HTML中都是预定义标签，而XML中没有预定义标签，全都是自定义标签，由来表示一些数据。就是自己给标签取名字
现在被json取代了
3、ajax特点1、优点
可以无需刷新页面而与服务器端进行通信 允许根据用户事件来更新部分页面内容
2、缺点
没有浏览历史，不能回退 存在跨域问题（同源）不能从一个网站访问另一个网站 SEO不友好(不能爬取数据)
4、HTTP协议 请求报文
重点是格式与参数，例如： 行 GET/s?ie=utf-8 HTTP/1.1头 Host:atguigu.com Cookie:name=guigu Content-type:application/x-www-form-urlencoded User-Agent:chrome 83空行体 username=admin&amp;password=admin
响应报文
行 HTTP/1.1(协议版本) 200(状态码) OK头 Content-Type:text/html;charset=utf-8 Content-length:2048 Content-encoding:gzip 空行 体 &lt;html&gt; &lt;head&gt; &lt;/head&gt; &lt;body&gt; xxx &lt;/body&gt; &lt;/html&gt;
5、express框架使用 在所在目录终端下输入
npm init --yes
安装express
npm i express
编写js文件
app.get app.post app.all代表接收所有形式的请求
// 1. 引入expressconst express = require(&#x27;express&#x27;);// 2. 创建应用对象const app = express();// 3. 创建路由规则// request是对请求报文的封装,reponse是对相应报文的封装app.get(&#x27;/&#x27;,(request,response)=&gt;&#123; response.send(&#x27;HELLO EXPRESS&#x27;);&#125;);// 4. 监听端口启动服务app.listen(8000,()=&gt;&#123; console.log(&quot;服务器已经启动,8080端口监听中...&quot;);&#125;)
运行
node filename(运行文件名包括后缀)
node express基本使用.js 6、通过原生js进行ajax操作页面：不刷新页面的情况下修改页面 &lt;html&gt; &lt;head&gt; &lt;meta charset=&quot;utf-8&quot;&gt; &lt;title&gt;AJAX GET请求&lt;/title&gt; &lt;style&gt; #result&#123; width:200px; height:100px; border:solid 1px #90b; &#125; &lt;/style&gt; &lt;/head&gt; &lt;body&gt; &lt;button&gt;点击发送请求&lt;/button&gt; &lt;div id=&quot;result&quot;&gt;&lt;/div&gt; &lt;/body&gt; &lt;script&gt; const btn = document.getElementsByTagName(&#x27;button&#x27;)[0]; const result = document.getElementById(&#x27;result&#x27;); // 绑定事件 btn.onclick = function()&#123; // 1. 创建对象 const xhr = new XMLHttpRequest(); // 2. 初始化 设置请求方式和 url xhr.open(&#x27;GET&#x27;,&#x27;http://127.0.0.1:8000/server&#x27;); // 3. 发送 xhr.send(); // 4. 事件绑定 处理服务器端返回的结果 // readystate 是 xhr对象中的属性,表示状态 // 0(未初始化) 1(open方法调用完毕) 2(send方法调用完毕) 3(服务端返回部分结果) 4(服务端返回所有结果) xhr.onreadystatechange = function()&#123; // 判断 服务端返回了所有的结果 if(xhr.readyState === 4)&#123; // 判断响应状态码 // 2xx 都表示成功 if(xhr.status &gt;= 200 &amp;&amp; xhr.status &lt;= 300)&#123; // 处理结果 行 头 空行 体 // 1. 响应行 // console.log(xhr.status); // console.log(xhr.statusText); // console.log(xhr.getAllResponseHeaders()); // console.log(xhr.response);// 响应体 result.innerHTML = xhr.response; &#125; &#125; &#125; &#125; &lt;/script&gt;&lt;/html&gt;
// 1. 引入expressconst express = require(&#x27;express&#x27;);// 2. 创建应用对象const app = express();// 3. 创建路由规则// request是对请求报文的封装,reponse是对相应报文的封装app.get(&#x27;/server&#x27;,(request,response)=&gt;&#123; //设置响应头 设置允许跨域 response.setHeader(&#x27;Access-Control-Allow-Origin&#x27;,&#x27;*&#x27;); // 设置响应体 response.send(&#x27;HELLO EXPRESS&#x27;);&#125;);// 4. 监听端口启动服务app.listen(8000,()=&gt;&#123; console.log(&quot;服务器已经启动,8080端口监听中...&quot;);&#125;)
设置get参数
xhr.open(&#x27;GET&#x27;,&#x27;http://127.0.0.1:8000/server?a=100&amp;b=200&#x27;);
ajax发送post请求
xhr.open(&#x27;POST&#x27;,&#x27;http://127.0.0.1:8000/server&#x27;);// 格式灵活,服务器端能处理即可 传输信息xhr.send(&#x27;a=100&amp;b=200&#x27;);
设置请求头，身份校验的信息通常放在这里
// 设置请求头// Content-Type 设置请求体内容类型xhr.setRequestHeader(&#x27;Content-Type&#x27;,&#x27;application/x-www-form-urlencoded&#x27;);xhr.setRequestHeader(&#x27;name&#x27;,&#x27;2dog&#x27;);
在服务器端如果想要接收自定义的内容 比如name,需要设置response的响应头(自定义的setHeader也可以传入)response.setHeader(&#x27;Access-Control-Allow-Headers&#x27;,&#x27;*&#x27;);
服务器端响应JSON数据
服务器端 const data = &#123; name:&#x27;dog&#x27;&#125;;let str = JSON.stringify(data);response.send(str);
前端接收 1. 手动转化let data = JSON.parse(xhr.response);result.innerHTML = data.name;2. 改变响应体类型xhr.responseType = &#x27;json&#x27;;xhr.onreadystatechange = function()&#123; if(xhr.readyState == 4)&#123; if(xhr.status &gt;= 200 &amp;&amp; xhr.status &lt;= 300)&#123; // 直接使用 result.innerHTML = xhr.response.name; &#125; &#125;&#125;
7、nodemon工具可以在修改完服务器端代码后 帮助自动重启服务器端 // 下载nodemonnpm install -g nodemon// 启动不再使用 npm server.jsnodemon server.js
8、ajax解决IE缓存问题ajax在服务端更新后，理应浏览器的数据也被更新，但是IE浏览器存在缓存问题(chrome就没有),所以需要处理，如下是一种方式 xhr.open(&#x27;GET&#x27;,&#x27;http://127.0.0.1:8000/ie?t=&#x27;+Date.now());
9、超时与网络异常// 超时设置xhr.timeout = 2000;xhr.ontimeout = function()&#123; alert(&#x27;网络超时&#x27;);&#125;// 网络异常问题xhr.onerror = function()&#123; alert(&#x27;你的网络似乎出现了一点问题&#x27;);&#125;
10、手动取消请求 请求成功需要时间,如果在请求成功前想要关闭，可以使用该方法
let x = null;btns[0].onclick = function()&#123; x = new XMLHttpRequest(); x.open(&#x27;get&#x27;,&#x27;http://127.0.0.1:8000/delay&#x27;); x.send();&#125;// 手动关闭 调用abort()方法btns[1].onclick = function()&#123; x.abort();&#125;
11、求情重复发送问题const btns = document.querySelectorAll(&#x27;button&#x27;);let x = null;// 标识变量 是否正在发送AJAX请求let isSending = false;btns[0].onclick = function()&#123; // 如果正在发送取消原来的 if(isSending)&#123; x.abort(); &#125; x = new XMLHttpRequest(); isSending = true; x.open(&#x27;get&#x27;,&#x27;http://127.0.0.1:8000/delay&#x27;); x.send(); x.onreadystatechange = function()&#123; // 只需判断状态码是否为4即可 if(x.readyState === 4)&#123; isSending = false; &#125; &#125;&#125;
12、jQuery发送AJAX请求$(&#x27;button&#x27;).eq(0).click(function()&#123; $.get(&#x27;http://127.0.0.1:8000/jquery-server&#x27;,&#123;a:100,b:200&#125;,function(data)&#123; console.log(data); &#125;,&#x27;json&#x27;);&#125;);$(&#x27;button&#x27;).eq(1).click(function()&#123; $.post(&#x27;http://127.0.0.1:8000/jquery-server&#x27;,&#123;a:100,b:200&#125;,function(data)&#123; console.log(data); &#125;)&#125;)
服务器端 app.all(&#x27;/jquery-server&#x27;,(request,response)=&gt;&#123; //设置响应头 设置允许跨域 response.setHeader(&#x27;Access-Control-Allow-Origin&#x27;,&#x27;*&#x27;); const data = &#123;name:&#x27;尚硅谷&#x27;&#125;; response.send(JSON.stringify(data));&#125;);
返回结果 不指定json返回的是字符串
13、jQuery通用方法发送AJAX请求$.ajax(&#123; url:&#x27;http://127.0.0.1:8000/jquery-server&#x27;, data:&#123; a:100, b:200 &#125;, type:&#x27;GET&#x27;, // 响应体结果类型 dataType:&#x27;json&#x27;, // 超时时间 超时后被error捕获 timeout:200, success:function(data)&#123; console.log(data); &#125;, error:function()&#123; console.log(&#x27;出错啦&#x27;) &#125;, // 头信息 headers:&#123; c:100 &#125;&#125;)
14、axios发送get、post请求BootCDN - Bootstrap 中文网开源项目免费 CDN 加速服务 引入axios axios文档 github地址 // 配置 baseURLaxios.defaults.baseURL = &#x27;http://127.0.0.1:8000&#x27;;btns[0].onclick = function()&#123; axios.get(&#x27;/axios-server&#x27;,&#123; params:&#123; id:100, vip:7 &#125;, headers:&#123; age:20 &#125; &#125;).then(value =&gt; &#123; console.log(value); &#125;)&#125;;btns[1].onclick = function()&#123; axios.post(&#x27;/axios-server&#x27;,&#123; username:&#x27;admin&#x27;, password:&#x27;admin&#x27; &#125;,&#123; params:&#123; id:200, vip:9 &#125;, headers:&#123; height:180, weight:180 &#125; &#125;)&#125;
15、axios函数发送AJAX请求params参数会直接拼接在url上面， ?vip=10&amp;level=30 btns[2].onclick = function()&#123; axios(&#123; // 请求方法 method:&#x27;POST&#x27;, url:&#x27;/axios-server&#x27;, params:&#123; vip:10, level:30 &#125;, // 请求头 headers:&#123; a:100, b:200 &#125;, // 请求体 data:&#123; username:&#x27;admin&#x27;, password:&#x27;admin&#x27; &#125; &#125;).then(response =&gt; &#123; console.log(response); console.log(response.status); console.log(response.statusText); console.log(response.headers); console.log(response.data); &#125;)&#125;
16、fetch方法发送AJAX请求WindowOrWorkerGlobalScope接口方法：fetch()_w3cschool btn.onclick = function()&#123; fetch(&#x27;http://127.0.0.1:8000/fetch-server&#x27;,&#123; method:&#x27;post&#x27;, headers:&#123; name:&#x27;dog&#x27; &#125;, body:&#x27;username=10&amp;password=20&#x27; &#125;).then(response =&gt; &#123; return response.json(); &#125;).then(response =&gt; &#123; console.log(response); &#125;)&#125;
